import React, { useEffect, useState, useCallback } from 'react';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';
import Toast from '../components/Toast';

const COLORS = ['#6366f1','#10b981','#3b82f6','#f59e0b','#ec4899','#8b5cf6','#14b8a6','#ef4444','#f97316','#06b6d4','#c9a84c','#84cc16'];

export default function Categories() {
  const { user } = useAuth();
  const isStaff = user?.userType === 'user';
  const isLibrarian = user?.role === 'librarian';
  const [categories, setCategories] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(false);
  const [editing, setEditing] = useState<any>(null);
  const [form, setForm] = useState({ name:'', description:'', color:'#6366f1' });
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');
  const [toast, setToast] = useState<any>(null);

  const load = useCallback(()=>{ api.get('/categories').then(r=>{setCategories(r.data.data||[]);setLoading(false);}).catch(()=>setLoading(false)); },[]);
  useEffect(()=>{load();},[load]);

  const openAdd = () => { setEditing(null); setForm({name:'',description:'',color:'#6366f1'}); setError(''); setModal(true); };
  const openEdit = (cat:any) => { setEditing(cat); setForm({name:cat.name, description:cat.description||'', color:cat.color}); setError(''); setModal(true); };

  const save = async () => {
    if (!form.name.trim()) { setError('Name required!'); return; }
    setSaving(true); setError('');
    try {
      if (editing) { await api.put(`/categories/${editing.id}`, form); setToast({message:`"${form.name}" updated`,type:'success'}); }
      else { await api.post('/categories', form); setToast({message:`"${form.name}" created!`,type:'success'}); }
      setModal(false); load();
    } catch(e:any) { setError(e.response?.data?.message||'Error'); }
    finally { setSaving(false); }
  };

  const del = async (cat:any) => {
    if (cat.book_count>0) { setToast({message:`Cannot delete "${cat.name}" — has ${cat.book_count} books`,type:'warning'}); return; }
    if (!window.confirm(`Delete "${cat.name}"?`)) return;
    try { await api.delete(`/categories/${cat.id}`); setToast({message:'Deleted',type:'success'}); load(); }
    catch { setToast({message:'Failed',type:'error'}); }
  };

  const inp:React.CSSProperties = {width:'100%',padding:'12px 14px',background:'rgba(255,255,255,0.05)',border:'1.5px solid rgba(255,255,255,0.1)',borderRadius:10,fontSize:14,color:'#f0eee8',fontFamily:'inherit',outline:'none',transition:'all .2s',boxSizing:'border-box'};
  const lbl:React.CSSProperties = {display:'block',fontSize:11,fontWeight:700,color:'rgba(255,255,255,0.4)',marginBottom:7,letterSpacing:'1px',textTransform:'uppercase'};

  return (
    <div className="page-enter" style={{padding:'32px 36px'}}>
      {toast && <Toast message={toast.message} type={toast.type} onClose={()=>setToast(null)} />}
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:28}}>
        <div>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:32,fontWeight:700,color:'var(--text)'}}>Categories</h1>
          <p style={{color:'var(--text-dim)',fontSize:13,marginTop:4}}>{categories.length} categories</p>
        </div>
        {isStaff && <button className="btn-primary" onClick={openAdd}>+ Add Category</button>}
      </div>

      {loading ? <div style={{display:'flex',justifyContent:'center',padding:80}}><div style={{width:36,height:36,border:'3px solid #c9a84c',borderTopColor:'transparent',borderRadius:'50%',animation:'spin 1s linear infinite'}}/></div> : (
        <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fill,minmax(220px,1fr))',gap:16}}>
          {categories.length ? categories.map(cat=>(
            <div key={cat.id} style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:22,transition:'all .2s'}}
              onMouseEnter={e=>{(e.currentTarget as any).style.borderColor=cat.color+'55';(e.currentTarget as any).style.transform='translateY(-3px)';(e.currentTarget as any).style.boxShadow=`0 12px 32px rgba(0,0,0,0.3)`;}}
              onMouseLeave={e=>{(e.currentTarget as any).style.borderColor='rgba(255,255,255,0.07)';(e.currentTarget as any).style.transform='none';(e.currentTarget as any).style.boxShadow='none';}}>
              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16}}>
                <div style={{width:50,height:50,borderRadius:14,background:cat.color+'1a',border:`1px solid ${cat.color}33`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:24}}>📂</div>
                {isStaff && (
                  <div style={{display:'flex',gap:6}}>
                    <button onClick={()=>openEdit(cat)} style={{padding:'6px 10px',background:'rgba(255,255,255,0.06)',border:'1px solid rgba(255,255,255,0.08)',borderRadius:8,fontSize:12,cursor:'pointer',color:'rgba(255,255,255,0.5)',transition:'all .2s'}}>✏️</button>
                    {isLibrarian && <button onClick={()=>del(cat)} style={{padding:'6px 10px',background:'rgba(239,68,68,0.1)',border:'1px solid rgba(239,68,68,0.2)',borderRadius:8,fontSize:12,cursor:'pointer',color:'#f87171',transition:'all .2s'}}>🗑️</button>}
                  </div>
                )}
              </div>
              <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:'var(--text)',marginBottom:6}}>{cat.name}</h3>
              <p style={{fontSize:13,color:'var(--text-dim)',lineHeight:1.5,marginBottom:16,minHeight:38}}>{cat.description||'No description'}</p>
              <div style={{borderTop:'1px solid rgba(255,255,255,0.06)',paddingTop:14,display:'flex',justifyContent:'space-between',alignItems:'center'}}>
                <div>
                  <span style={{fontFamily:"'Playfair Display',serif",fontSize:26,fontWeight:700,color:cat.color}}>{cat.book_count}</span>
                  <span style={{fontSize:12,color:'var(--text-dim)',marginLeft:5}}>books</span>
                </div>
                <div style={{width:10,height:10,borderRadius:'50%',background:cat.color,boxShadow:`0 0 8px ${cat.color}88`}}/>
              </div>
            </div>
          )) : (
            <div style={{gridColumn:'1/-1',textAlign:'center',padding:80,color:'rgba(255,255,255,0.2)'}}>
              <div style={{fontSize:52,marginBottom:14}}>📂</div>
              <p style={{fontSize:16,fontWeight:600,color:'var(--text-dim)'}}>No categories yet</p>
              {isStaff && <p style={{fontSize:13,marginTop:8,color:'rgba(255,255,255,0.2)'}}>Click "+ Add Category" to create one</p>}
            </div>
          )}
        </div>
      )}

      {modal && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.75)',backdropFilter:'blur(6px)',zIndex:1000,display:'flex',alignItems:'center',justifyContent:'center',padding:20}}>
          <div style={{background:'var(--bg2)',border:'1px solid rgba(255,255,255,0.1)',borderRadius:22,padding:32,width:'100%',maxWidth:440}}>
            <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:24}}>
              <h2 style={{fontFamily:"'Playfair Display',serif",fontSize:22,fontWeight:700,color:'var(--text)'}}>{editing?'Edit Category':'Add Category'}</h2>
              <button onClick={()=>setModal(false)} style={{background:'rgba(255,255,255,0.08)',border:'none',color:'rgba(255,255,255,0.5)',width:34,height:34,borderRadius:9,cursor:'pointer',fontSize:16}}>✕</button>
            </div>
            {error && <div style={{background:'rgba(239,68,68,0.1)',border:'1px solid rgba(239,68,68,0.2)',color:'#f87171',padding:'10px 14px',borderRadius:9,fontSize:13,marginBottom:14}}>{error}</div>}
            <div style={{marginBottom:16}}>
              <label style={lbl}>Name *</label>
              <input style={inp} value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="e.g. Science & Technology" />
            </div>
            <div style={{marginBottom:16}}>
              <label style={lbl}>Description</label>
              <textarea style={{...inp,minHeight:70,resize:'vertical'}} value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))} placeholder="Brief description..." />
            </div>
            <div style={{marginBottom:24}}>
              <label style={lbl}>Color</label>
              <div style={{display:'flex',gap:8,flexWrap:'wrap',marginBottom:12}}>
                {COLORS.map(c=>(
                  <button key={c} onClick={()=>setForm(f=>({...f,color:c}))} style={{width:30,height:30,borderRadius:8,background:c,border:form.color===c?`3px solid #fff`:'3px solid transparent',cursor:'pointer',transition:'all .15s',boxShadow:form.color===c?`0 0 10px ${c}88`:'none'}}/>
                ))}
              </div>
              <div style={{display:'flex',alignItems:'center',gap:12,padding:'12px 14px',background:'rgba(255,255,255,0.04)',borderRadius:10,border:'1px solid rgba(255,255,255,0.08)'}}>
                <div style={{width:36,height:36,borderRadius:10,background:form.color+'1a',border:`1px solid ${form.color}44`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:18}}>📂</div>
                <span style={{fontSize:14,color:'rgba(255,255,255,0.5)'}}>{form.name||'Category Preview'}</span>
                <div style={{width:8,height:8,borderRadius:'50%',background:form.color,marginLeft:'auto',boxShadow:`0 0 8px ${form.color}`}}/>
              </div>
            </div>
            <div style={{display:'flex',gap:10}}>
              <button onClick={()=>setModal(false)} className="btn-ghost" style={{flex:1}}>Cancel</button>
              <button onClick={save} disabled={saving} className="btn-primary" style={{flex:2}}>{saving?'Saving...':editing?'Update':'Create Category'}</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
